41	ngx_int_t
42	ngx_output_chain(ngx_output_chain_ctx_t *ctx, ngx_chain_t *in)
43	{
44	    off_t         bsize;
45	    ngx_int_t     rc, last;
46	    ngx_chain_t  *cl, *out, **last_out;
47	
48	    if (ctx->in == NULL && ctx->busy == NULL
49	#if (NGX_HAVE_FILE_AIO || NGX_THREADS)
50	        && !ctx->aio
51	#endif
52	       )
53	    {
54	        /*
55	         * the short path for the case when the ctx->in and ctx->busy chains
56	         * are empty, the incoming chain is empty too or has the single buf
57	         * that does not require the copy
58	         */
59	
60	        if (in == NULL) {
61	            return ctx->output_filter(ctx->filter_ctx, in);
62	        }
63	
64	        if (in->next == NULL
65	#if (NGX_SENDFILE_LIMIT)
66	            && !(in->buf->in_file && in->buf->file_last > NGX_SENDFILE_LIMIT)
67	#endif
68	            && ngx_output_chain_as_is(ctx, in->buf))
69	        {
70	            return ctx->output_filter(ctx->filter_ctx, in);
71	        }
72	    }
73	
74	    /* add the incoming buf to the chain ctx->in */
75	
76	    if (in) {
77	        if (ngx_output_chain_add_copy(ctx->pool, &ctx->in, in) == NGX_ERROR) {
78	            return NGX_ERROR;
79	        }
80	    }
81	
82	    out = NULL;
83	    last_out = &out;
84	    last = NGX_NONE;
85	
86	    for ( ;; ) {
87	
88	#if (NGX_HAVE_FILE_AIO || NGX_THREADS)
89	        if (ctx->aio) {
90	            return NGX_AGAIN;
91	        }
92	#endif
93	
94	        while (ctx->in) {
95	
96	            /*
97	             * cycle while there are the ctx->in bufs
98	             * and there are the free output bufs to copy in
99	             */
100	
101	            bsize = ngx_buf_size(ctx->in->buf);
102	
103	            if (bsize == 0 && !ngx_buf_special(ctx->in->buf)) {
104	
105	                ngx_log_error(NGX_LOG_ALERT, ctx->pool->log, 0,
106	                              "zero size buf in output "
107	                              "t:%d r:%d f:%d %p %p-%p %p %O-%O",
108	                              ctx->in->buf->temporary,
109	                              ctx->in->buf->recycled,
110	                              ctx->in->buf->in_file,
111	                              ctx->in->buf->start,
112	                              ctx->in->buf->pos,
113	                              ctx->in->buf->last,
114	                              ctx->in->buf->file,
115	                              ctx->in->buf->file_pos,
116	                              ctx->in->buf->file_last);
117	
118	                ngx_debug_point();
119	
120	                cl = ctx->in;
121	                ctx->in = cl->next;
122	
123	                ngx_free_chain(ctx->pool, cl);
124	
125	                continue;
126	            }
127	
128	            if (bsize < 0) {
129	
130	                ngx_log_error(NGX_LOG_ALERT, ctx->pool->log, 0,
131	                              "negative size buf in output "
132	                              "t:%d r:%d f:%d %p %p-%p %p %O-%O",
133	                              ctx->in->buf->temporary,
134	                              ctx->in->buf->recycled,
135	                              ctx->in->buf->in_file,
136	                              ctx->in->buf->start,
137	                              ctx->in->buf->pos,
138	                              ctx->in->buf->last,
139	                              ctx->in->buf->file,
140	                              ctx->in->buf->file_pos,
141	                              ctx->in->buf->file_last);
142	
143	                ngx_debug_point();
144	
145	                return NGX_ERROR;
146	            }
147	
148	            if (ngx_output_chain_as_is(ctx, ctx->in->buf)) {
149	
150	                /* move the chain link to the output chain */
151	
152	                cl = ctx->in;
153	                ctx->in = cl->next;
154	
155	                *last_out = cl;
156	                last_out = &cl->next;
157	                cl->next = NULL;
158	
159	                continue;
160	            }
161	
162	            if (ctx->buf == NULL) {
163	
164	                rc = ngx_output_chain_align_file_buf(ctx, bsize);
165	
166	                if (rc == NGX_ERROR) {
167	                    return NGX_ERROR;
168	                }
169	
170	                if (rc != NGX_OK) {
171	
172	                    if (ctx->free) {
173	
174	                        /* get the free buf */
175	
176	                        cl = ctx->free;
177	                        ctx->buf = cl->buf;
178	                        ctx->free = cl->next;
179	
180	                        ngx_free_chain(ctx->pool, cl);
181	
182	                    } else if (out || ctx->allocated == ctx->bufs.num) {
183	
184	                        break;
185	
186	                    } else if (ngx_output_chain_get_buf(ctx, bsize) != NGX_OK) {
187	                        return NGX_ERROR;
188	                    }
189	                }
190	            }
191	
192	            rc = ngx_output_chain_copy_buf(ctx);
193	
194	            if (rc == NGX_ERROR) {
195	                return rc;
196	            }
197	
198	            if (rc == NGX_AGAIN) {
199	                if (out) {
200	                    break;
201	                }
202	
203	                return rc;
204	            }
205	
206	            /* delete the completed buf from the ctx->in chain */
207	
208	            if (ngx_buf_size(ctx->in->buf) == 0) {
209	                cl = ctx->in;
210	                ctx->in = cl->next;
211	
212	                ngx_free_chain(ctx->pool, cl);
213	            }
214	
215	            cl = ngx_alloc_chain_link(ctx->pool);
216	            if (cl == NULL) {
217	                return NGX_ERROR;
218	            }
219	
220	            cl->buf = ctx->buf;
221	            cl->next = NULL;
222	            *last_out = cl;
223	            last_out = &cl->next;
224	            ctx->buf = NULL;
225	        }
226	
227	        if (out == NULL && last != NGX_NONE) {
228	
229	            if (ctx->in) {
230	                return NGX_AGAIN;
231	            }
232	
233	            return last;
234	        }
235	
236	        last = ctx->output_filter(ctx->filter_ctx, out);
237	
238	        if (last == NGX_ERROR || last == NGX_DONE) {
239	            return last;
240	        }
241	
242	        ngx_chain_update_chains(ctx->pool, &ctx->free, &ctx->busy, &out,
243	                                ctx->tag);
244	        last_out = &out;
245	    }
246	}
