249	static ngx_inline ngx_int_t
250	ngx_output_chain_as_is(ngx_output_chain_ctx_t *ctx, ngx_buf_t *buf)
251	{
252	    ngx_uint_t  sendfile;
253	
254	    if (ngx_buf_special(buf)) {
255	        return 1;
256	    }
257	
258	#if (NGX_THREADS)
259	    if (buf->in_file) {
260	        buf->file->thread_handler = ctx->thread_handler;
261	        buf->file->thread_ctx = ctx->filter_ctx;
262	    }
263	#endif
264	
265	    sendfile = ctx->sendfile;
266	
267	#if (NGX_SENDFILE_LIMIT)
268	
269	    if (buf->in_file && buf->file_pos >= NGX_SENDFILE_LIMIT) {
270	        sendfile = 0;
271	    }
272	
273	#endif
274	
275	#if !(NGX_HAVE_SENDFILE_NODISKIO)
276	
277	    /*
278	     * With DIRECTIO, disable sendfile() unless sendfile(SF_NOCACHE)
279	     * is available.
280	     */
281	
282	    if (buf->in_file && buf->file->directio) {
283	        sendfile = 0;
284	    }
285	
286	#endif
287	
288	    if (!sendfile) {
289	
290	        if (!ngx_buf_in_memory(buf)) {
291	            return 0;
292	        }
293	
294	        buf->in_file = 0;
295	    }
296	
297	    if (ctx->need_in_memory && !ngx_buf_in_memory(buf)) {
298	        return 0;
299	    }
300	
301	    if (ctx->need_in_temp && (buf->memory || buf->mmap)) {
302	        return 0;
303	    }
304	
305	    return 1;
306	}
