309	static ngx_int_t
310	ngx_output_chain_add_copy(ngx_pool_t *pool, ngx_chain_t **chain,
311	    ngx_chain_t *in)
312	{
313	    ngx_chain_t  *cl, **ll;
314	#if (NGX_SENDFILE_LIMIT)
315	    ngx_buf_t    *b, *buf;
316	#endif
317	
318	    ll = chain;
319	
320	    for (cl = *chain; cl; cl = cl->next) {
321	        ll = &cl->next;
322	    }
323	
324	    while (in) {
325	
326	        cl = ngx_alloc_chain_link(pool);
327	        if (cl == NULL) {
328	            return NGX_ERROR;
329	        }
330	
331	#if (NGX_SENDFILE_LIMIT)
332	
333	        buf = in->buf;
334	
335	        if (buf->in_file
336	            && buf->file_pos < NGX_SENDFILE_LIMIT
337	            && buf->file_last > NGX_SENDFILE_LIMIT)
338	        {
339	            /* split a file buf on two bufs by the sendfile limit */
340	
341	            b = ngx_calloc_buf(pool);
342	            if (b == NULL) {
343	                return NGX_ERROR;
344	            }
345	
346	            ngx_memcpy(b, buf, sizeof(ngx_buf_t));
347	
348	            if (ngx_buf_in_memory(buf)) {
349	                buf->pos += (ssize_t) (NGX_SENDFILE_LIMIT - buf->file_pos);
350	                b->last = buf->pos;
351	            }
352	
353	            buf->file_pos = NGX_SENDFILE_LIMIT;
354	            b->file_last = NGX_SENDFILE_LIMIT;
355	
356	            cl->buf = b;
357	
358	        } else {
359	            cl->buf = buf;
360	            in = in->next;
361	        }
362	
363	#else
364	        cl->buf = in->buf;
365	        in = in->next;
366	
367	#endif
368	
369	        cl->next = NULL;
370	        *ll = cl;
371	        ll = &cl->next;
372	    }
373	
374	    return NGX_OK;
375	}
