378	static ngx_int_t
379	ngx_output_chain_align_file_buf(ngx_output_chain_ctx_t *ctx, off_t bsize)
380	{
381	    size_t      size;
382	    ngx_buf_t  *in;
383	
384	    in = ctx->in->buf;
385	
386	    if (in->file == NULL || !in->file->directio) {
387	        return NGX_DECLINED;
388	    }
389	
390	    ctx->directio = 1;
391	
392	    size = (size_t) (in->file_pos - (in->file_pos & ~(ctx->alignment - 1)));
393	
394	    if (size == 0) {
395	
396	        if (bsize >= (off_t) ctx->bufs.size) {
397	            return NGX_DECLINED;
398	        }
399	
400	        size = (size_t) bsize;
401	
402	    } else {
403	        size = (size_t) ctx->alignment - size;
404	
405	        if ((off_t) size > bsize) {
406	            size = (size_t) bsize;
407	        }
408	    }
409	
410	    ctx->buf = ngx_create_temp_buf(ctx->pool, size);
411	    if (ctx->buf == NULL) {
412	        return NGX_ERROR;
413	    }
414	
415	    /*
416	     * we do not set ctx->buf->tag, because we do not want
417	     * to reuse the buf via ctx->free list
418	     */
419	
420	#if (NGX_HAVE_ALIGNED_DIRECTIO)
421	    ctx->unaligned = 1;
422	#endif
423	
424	    return NGX_OK;
425	}
