428	static ngx_int_t
429	ngx_output_chain_get_buf(ngx_output_chain_ctx_t *ctx, off_t bsize)
430	{
431	    size_t       size;
432	    ngx_buf_t   *b, *in;
433	    ngx_uint_t   recycled;
434	
435	    in = ctx->in->buf;
436	    size = ctx->bufs.size;
437	    recycled = 1;
438	
439	    if (in->last_in_chain) {
440	
441	        if (bsize < (off_t) size) {
442	
443	            /*
444	             * allocate a small temp buf for a small last buf
445	             * or its small last part
446	             */
447	
448	            size = (size_t) bsize;
449	            recycled = 0;
450	
451	        } else if (!ctx->directio
452	                   && ctx->bufs.num == 1
453	                   && (bsize < (off_t) (size + size / 4)))
454	        {
455	            /*
456	             * allocate a temp buf that equals to a last buf,
457	             * if there is no directio, the last buf size is lesser
458	             * than 1.25 of bufs.size and the temp buf is single
459	             */
460	
461	            size = (size_t) bsize;
462	            recycled = 0;
463	        }
464	    }
465	
466	    b = ngx_calloc_buf(ctx->pool);
467	    if (b == NULL) {
468	        return NGX_ERROR;
469	    }
470	
471	    if (ctx->directio) {
472	
473	        /*
474	         * allocate block aligned to a disk sector size to enable
475	         * userland buffer direct usage conjunctly with directio
476	         */
477	
478	        b->start = ngx_pmemalign(ctx->pool, size, (size_t) ctx->alignment);
479	        if (b->start == NULL) {
480	            return NGX_ERROR;
481	        }
482	
483	    } else {
484	        b->start = ngx_palloc(ctx->pool, size);
485	        if (b->start == NULL) {
486	            return NGX_ERROR;
487	        }
488	    }
489	
490	    b->pos = b->start;
491	    b->last = b->start;
492	    b->end = b->last + size;
493	    b->temporary = 1;
494	    b->tag = ctx->tag;
495	    b->recycled = recycled;
496	
497	    ctx->buf = b;
498	    ctx->allocated++;
499	
500	    return NGX_OK;
501	}
