503	
504	static ngx_int_t
505	ngx_output_chain_copy_buf(ngx_output_chain_ctx_t *ctx)
506	{
507	    off_t        size;
508	    ssize_t      n;
509	    ngx_buf_t   *src, *dst;
510	    ngx_uint_t   sendfile;
511	
512	    src = ctx->in->buf;
513	    dst = ctx->buf;
514	
515	    size = ngx_buf_size(src);
516	    size = ngx_min(size, dst->end - dst->pos);
517	
518	    sendfile = ctx->sendfile && !ctx->directio;
519	
520	#if (NGX_SENDFILE_LIMIT)
521	
522	    if (src->in_file && src->file_pos >= NGX_SENDFILE_LIMIT) {
523	        sendfile = 0;
524	    }
525	
526	#endif
527	
528	    if (ngx_buf_in_memory(src)) {
529	        ngx_memcpy(dst->pos, src->pos, (size_t) size);
530	        src->pos += (size_t) size;
531	        dst->last += (size_t) size;
532	
533	        if (src->in_file) {
534	
535	            if (sendfile) {
536	                dst->in_file = 1;
537	                dst->file = src->file;
538	                dst->file_pos = src->file_pos;
539	                dst->file_last = src->file_pos + size;
540	
541	            } else {
542	                dst->in_file = 0;
543	            }
544	
545	            src->file_pos += size;
546	
547	        } else {
548	            dst->in_file = 0;
549	        }
550	
551	        if (src->pos == src->last) {
552	            dst->flush = src->flush;
553	            dst->last_buf = src->last_buf;
554	            dst->last_in_chain = src->last_in_chain;
555	
556	        } else {
557	            dst->flush = 0;
558	            dst->last_buf = 0;
559	            dst->last_in_chain = 0;
560	        }
561	
562	    } else {
563	
564	#if (NGX_HAVE_ALIGNED_DIRECTIO)
565	
566	        if (ctx->unaligned) {
567	            if (ngx_directio_off(src->file->fd) == NGX_FILE_ERROR) {
568	                ngx_log_error(NGX_LOG_ALERT, ctx->pool->log, ngx_errno,
569	                              ngx_directio_off_n " \"%s\" failed",
570	                              src->file->name.data);
571	            }
572	        }
573	
574	#endif
575	
576	#if (NGX_HAVE_FILE_AIO)
577	        if (ctx->aio_handler) {
578	            n = ngx_file_aio_read(src->file, dst->pos, (size_t) size,
579	                                  src->file_pos, ctx->pool);
580	            if (n == NGX_AGAIN) {
581	                ctx->aio_handler(ctx, src->file);
582	                return NGX_AGAIN;
583	            }
584	
585	        } else
586	#endif
587	#if (NGX_THREADS)
588	        if (ctx->thread_handler) {
589	            src->file->thread_task = ctx->thread_task;
590	            src->file->thread_handler = ctx->thread_handler;
591	            src->file->thread_ctx = ctx->filter_ctx;
592	
593	            n = ngx_thread_read(src->file, dst->pos, (size_t) size,
594	                                src->file_pos, ctx->pool);
595	            if (n == NGX_AGAIN) {
596	                ctx->thread_task = src->file->thread_task;
597	                return NGX_AGAIN;
598	            }
599	
600	        } else
601	#endif
602	        {
603	            n = ngx_read_file(src->file, dst->pos, (size_t) size,
604	                              src->file_pos);
605	        }
606	
607	#if (NGX_HAVE_ALIGNED_DIRECTIO)
608	
609	        if (ctx->unaligned) {
610	            ngx_err_t  err;
611	
612	            err = ngx_errno;
613	
614	            if (ngx_directio_on(src->file->fd) == NGX_FILE_ERROR) {
615	                ngx_log_error(NGX_LOG_ALERT, ctx->pool->log, ngx_errno,
616	                              ngx_directio_on_n " \"%s\" failed",
617	                              src->file->name.data);
618	            }
619	
620	            ngx_set_errno(err);
621	
622	            ctx->unaligned = 0;
623	        }
624	
625	#endif
626	
627	        if (n == NGX_ERROR) {
628	            return (ngx_int_t) n;
629	        }
630	
631	        if (n != size) {
632	            ngx_log_error(NGX_LOG_ALERT, ctx->pool->log, 0,
633	                          ngx_read_file_n " read only %z of %O from \"%s\"",
634	                          n, size, src->file->name.data);
635	            return NGX_ERROR;
636	        }
637	
638	        dst->last += n;
639	
640	        if (sendfile) {
641	            dst->in_file = 1;
642	            dst->file = src->file;
643	            dst->file_pos = src->file_pos;
644	            dst->file_last = src->file_pos + n;
645	
646	        } else {
647	            dst->in_file = 0;
648	        }
649	
650	        src->file_pos += n;
651	
652	        if (src->file_pos == src->file_last) {
653	            dst->flush = src->flush;
654	            dst->last_buf = src->last_buf;
655	            dst->last_in_chain = src->last_in_chain;
656	
657	        } else {
658	            dst->flush = 0;
659	            dst->last_buf = 0;
660	            dst->last_in_chain = 0;
661	        }
662	    }
663	
664	    return NGX_OK;
665	}
666	
667	
668	ngx_int_t
669	ngx_chain_writer(void *data, ngx_chain_t *in)
670	{
671	    ngx_chain_writer_ctx_t *ctx = data;
672	
673	    off_t              size;
674	    ngx_chain_t       *cl, *ln, *chain;
675	    ngx_connection_t  *c;
676	
677	    c = ctx->connection;
678	
679	    for (size = 0; in; in = in->next) {
680	
681	        if (ngx_buf_size(in->buf) == 0 && !ngx_buf_special(in->buf)) {
682	
683	            ngx_log_error(NGX_LOG_ALERT, ctx->pool->log, 0,
684	                          "zero size buf in chain writer "
685	                          "t:%d r:%d f:%d %p %p-%p %p %O-%O",
686	                          in->buf->temporary,
687	                          in->buf->recycled,
688	                          in->buf->in_file,
689	                          in->buf->start,
690	                          in->buf->pos,
691	                          in->buf->last,
692	                          in->buf->file,
693	                          in->buf->file_pos,
694	                          in->buf->file_last);
695	
696	            ngx_debug_point();
697	
698	            continue;
699	        }
700	
701	        if (ngx_buf_size(in->buf) < 0) {
702	
703	            ngx_log_error(NGX_LOG_ALERT, ctx->pool->log, 0,
704	                          "negative size buf in chain writer "
705	                          "t:%d r:%d f:%d %p %p-%p %p %O-%O",
706	                          in->buf->temporary,
707	                          in->buf->recycled,
708	                          in->buf->in_file,
709	                          in->buf->start,
710	                          in->buf->pos,
711	                          in->buf->last,
712	                          in->buf->file,
713	                          in->buf->file_pos,
714	                          in->buf->file_last);
715	
716	            ngx_debug_point();
717	
718	            return NGX_ERROR;
719	        }
720	
721	        size += ngx_buf_size(in->buf);
722	
723	        ngx_log_debug2(NGX_LOG_DEBUG_CORE, c->log, 0,
724	                       "chain writer buf fl:%d s:%uO",
725	                       in->buf->flush, ngx_buf_size(in->buf));
726	
727	        cl = ngx_alloc_chain_link(ctx->pool);
728	        if (cl == NULL) {
729	            return NGX_ERROR;
730	        }
731	
732	        cl->buf = in->buf;
733	        cl->next = NULL;
734	        *ctx->last = cl;
735	        ctx->last = &cl->next;
736	    }
737	
738	    ngx_log_debug1(NGX_LOG_DEBUG_CORE, c->log, 0,
739	                   "chain writer in: %p", ctx->out);
740	
741	    for (cl = ctx->out; cl; cl = cl->next) {
742	
743	        if (ngx_buf_size(cl->buf) == 0 && !ngx_buf_special(cl->buf)) {
744	
745	            ngx_log_error(NGX_LOG_ALERT, ctx->pool->log, 0,
746	                          "zero size buf in chain writer "
747	                          "t:%d r:%d f:%d %p %p-%p %p %O-%O",
748	                          cl->buf->temporary,
749	                          cl->buf->recycled,
750	                          cl->buf->in_file,
751	                          cl->buf->start,
752	                          cl->buf->pos,
753	                          cl->buf->last,
754	                          cl->buf->file,
755	                          cl->buf->file_pos,
756	                          cl->buf->file_last);
757	
758	            ngx_debug_point();
759	
760	            continue;
761	        }
762	
763	        if (ngx_buf_size(cl->buf) < 0) {
764	
765	            ngx_log_error(NGX_LOG_ALERT, ctx->pool->log, 0,
766	                          "negative size buf in chain writer "
767	                          "t:%d r:%d f:%d %p %p-%p %p %O-%O",
768	                          cl->buf->temporary,
769	                          cl->buf->recycled,
770	                          cl->buf->in_file,
771	                          cl->buf->start,
772	                          cl->buf->pos,
773	                          cl->buf->last,
774	                          cl->buf->file,
775	                          cl->buf->file_pos,
776	                          cl->buf->file_last);
777	
778	            ngx_debug_point();
779	
780	            return NGX_ERROR;
781	        }
782	
783	        size += ngx_buf_size(cl->buf);
784	    }
785	
786	    if (size == 0 && !c->buffered) {
787	        return NGX_OK;
788	    }
789	
790	    chain = c->send_chain(c, ctx->out, ctx->limit);
791	
792	    ngx_log_debug1(NGX_LOG_DEBUG_CORE, c->log, 0,
793	                   "chain writer out: %p", chain);
794	
795	    if (chain == NGX_CHAIN_ERROR) {
796	        return NGX_ERROR;
797	    }
798	
799	    if (chain && c->write->ready) {
800	        ngx_post_event(c->write, &ngx_posted_next_events);
801	    }
802	
803	    for (cl = ctx->out; cl && cl != chain; /* void */) {
804	        ln = cl;
805	        cl = cl->next;
806	        ngx_free_chain(ctx->pool, ln);
807	    }
808	
809	    ctx->out = chain;
810	
811	    if (ctx->out == NULL) {
812	        ctx->last = &ctx->out;
813	
814	        if (!c->buffered) {
815	            return NGX_OK;
816	        }
817	    }
818	
819	    return NGX_AGAIN;
